--
-- Name: search_form_submissions(text); Type: FUNCTION; Schema: public; Owner: azureuser
--

CREATE FUNCTION public.search_form_submissions(search_term text) RETURNS TABLE("SubmissionId" uuid, "FormId" uuid, "FieldKey" text, "MatchedValue" text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH RECURSIVE submission_search(id, form_id, path, val) AS (
        -- Base Case
        SELECT 
            fs."Id",        -- Explicitly use 'fs' alias
            fs."FormId",    -- Explicitly use 'fs' alias
            ''::text, 
            fs."ResponseData"
        FROM "FormSubmissions" fs  -- Added alias 'fs' here
        WHERE fs."ResponseData"::text ILIKE '%' || search_term || '%'

        UNION ALL

        -- Recursive Step
        SELECT 
            t.id, 
            t.form_id,
            CASE 
                WHEN t.path = '' THEN kv.k 
                WHEN kv.is_array THEN t.path || '[' || kv.k || ']'
                ELSE t.path || '.' || kv.k 
            END,
            kv.v
        FROM submission_search t
        CROSS JOIN LATERAL (
            SELECT key AS k, value AS v, false AS is_array 
            FROM jsonb_each(t.val) 
            WHERE jsonb_typeof(t.val) = 'object'
            
            UNION ALL
            
            SELECT (idx-1)::text AS k, elem AS v, true AS is_array 
            FROM jsonb_array_elements(t.val) WITH ORDINALITY arr(elem, idx) 
            WHERE jsonb_typeof(t.val) = 'array'
        ) kv
    )
    SELECT 
        id,
        form_id,
        path,
        val #>> '{}'
    FROM submission_search
    WHERE 
        jsonb_typeof(val) NOT IN ('array', 'object')
        AND (val #>> '{}') ILIKE '%' || search_term || '%';
END;
$$;


